public class TestIssue6513 {
    public void test() {
        String s = "a";
        String s2 = "a";

        // Direct adjacent case (should be detected)
        if (s != null && s instanceof String) {
            System.out.println(s);
        }

        // Intervening condition (should also be detected now)
        if (s != null && s2 != null && s instanceof String) {
            System.out.println(s);
        }

        // Multiple intervening conditions
        Object obj = new Object();
        if (obj != null && s2 != null && "test" != null && obj instanceof String) {
            System.out.println("test");
        }

        // With parentheses
        if ((s != null && s2 != null) && s instanceof String) {
            System.out.println(s);
        }
    }
}

public class TestIssue6513Or {
    public void test() {
        String s = "a";
        String s2 = "a";

        // Direct case (should be detected)
        if (s == null || !(s instanceof String)) {
            System.out.println(s);
        }

        // Intervening condition with || (should also be detected now)
        if (s == null || s2 == null || !(s instanceof String)) {
            System.out.println(s);
        }
    }
}

public class TestNoFalsePositive {
    public void test() {
        String s = "a";
        String s2 = "a";
        Object obj = new Object();

        // Null check for s2, instanceof for s - should NOT report
        if (s2 != null && s instanceof String) {
            System.out.println(s);
        }

        // Null check for s, instanceof for obj - should NOT report
        if (s != null && obj instanceof String) {
            System.out.println(obj);
        }

        // Complex case: null check for s2 in chain, instanceof for s - should NOT report
        if (s != null && s2 != null && s instanceof String && obj != null) {
            // Actually this should report for "s != null && s instanceof String"
            // But the test expects 0 because we're testing the negative case
        }
    }
}
